insert into podcast_glossary (term, category, definition) values
('ARERA','regolatore','Autorità di Regolazione per Energia Reti e Ambiente. Dal 2018 ha ereditato le competenze dell''AEEGSI e aggiunto rifiuti. Struttura collegiale (5 membri + Presidente), mandato 7 anni.'),
('MASE','regolatore','Ministero dell''Ambiente e della Sicurezza Energetica (ex MITE, ex MiSE). Stabilisce l''indirizzo politico; ARERA regola tecnicamente.'),
('CSEA','regolatore','Cassa per i Servizi Energetici e Ambientali. È il tesoriere del sistema: incassa gli oneri di sistema, gestisce i conti di perequazione (morosità FUI, tutele graduali) e liquida gli ammontari ai venditori.'),
('Acquirente Unico','regolatore','AU. Società pubblica che gestisce l''approvvigionamento per la Maggior Tutela, il Portale Offerte, lo Sportello Consumatori e le aste del Servizio a Tutele Graduali.'),
('GME','regolatore','Gestore dei Mercati Energetici. Borsa dell''elettricità (MGP, PUN) e del gas (PSV).'),
('GSE','regolatore','Gestore dei Servizi Energetici. Si occupa di rinnovabili, incentivi, CER, Garanzie d''Origine (GO).'),
('Terna','regolatore','TSO elettrico. Gestisce la trasmissione AT/AAT e il dispacciamento.'),
('Snam','regolatore','TSO gas principale. Gestisce la rete nazionale di trasporto.'),
('SII','regolatore','Sistema Informativo Integrato. Gestito da Acquirente Unico, piattaforma centrale per tutte le comunicazioni tra venditori, distributori e TSO: switching, attivazioni, cessazioni, voltura.'),
('TIV','testi_integrati','Testo Integrato Vendita (elettrica). Delibera 362/2023/R/eel. Regola maggior tutela, tutele graduali, salvaguardia.'),
('TIVG','testi_integrati','Testo Integrato Vendita Gas. Delibera 100/2023/R/com. Regola tutela vulnerabilità gas, FUI, FDD, misura.'),
('TIF','testi_integrati','Testo Integrato Fatturazione. Delibera 463/2016/R/com. Tempistiche bollette, indennizzi per ritardi.'),
('TIMOE','testi_integrati','Testo Integrato Morosità Elettrica. Come si gestisce un cliente moroso, costituzione in mora, sospensione fornitura.'),
('TIMG','testi_integrati','Testo Integrato Morosità Gas. Equivalente del TIMOE per il gas.'),
('TIQV','testi_integrati','Testo Integrato Qualità Vendita. Standard di servizio ai clienti (tempi di risposta reclami, rettifiche).'),
('CCC','testi_integrati','Codice di Condotta Commerciale. Delibera 366/2018/R/com + aggiornamento 395/2024. Il galateo della vendita retail.'),
('TIS','testi_integrati','Testo Integrato Settlement. Le partite economiche del dispacciamento.'),
('TIDE','testi_integrati','Testo Integrato Dispacciamento Elettrico.'),
('TIUC','testi_integrati','Testo Integrato Unbundling Contabile. Obblighi di separazione contabile per le imprese verticalmente integrate.'),
('TIBEG','testi_integrati','Testo Integrato Bonus Elettrico e Gas. Regole del bonus sociale.'),
('Maggior Tutela','servizi','MT. Il vecchio mercato tutelato elettrico. Dal 1° luglio 2024 riservato solo ai clienti vulnerabili domestici. Prezzo fissato trimestralmente da ARERA.'),
('Tutela Gas','servizi','Finita il 1° gennaio 2024 per i non vulnerabili. I vulnerabili gas hanno accesso a un servizio di tutela specifico regolato dal TIVG.'),
('STG','servizi','Servizio a Tutele Graduali. Regime transitorio post-tutela. Tre sottocategorie: domestici non vulnerabili, microimprese, piccole imprese. Scade 31 marzo 2027.'),
('PLACET','servizi','Prezzo Libero a Condizioni Equiparate di Tutela. Delibera 555/2017/R/com. Offerta del mercato libero con condizioni contrattuali standardizzate ARERA; prezzo libero. Ogni venditore deve offrire almeno una PLACET Fissa e una Variabile, sia luce che gas.'),
('Salvaguardia','servizi','Per i clienti non domestici MT/BT che non hanno un contratto valido. Aggiudicata tramite asta nazionale biennale. Nuove regole DM 23 luglio 2024, delibera 388/2024.'),
('Mercato Libero','servizi','Tutto il resto. Oggi rappresenta il 92,6% dei volumi elettrici e il 78,2% dei POD (dati ARERA 2024).'),
('FUI','servizi','Fornitore di Ultima Istanza (gas). Assegnato tramite asta di AU a livello nazionale/macro-area. Subentra quando un cliente perde il venditore e ha diritto al servizio.'),
('FDD','servizi','Fornitore del Servizio di Default (gas). Altro tipo di fornitore di backup, attivato per clienti che non hanno diritto al FUI.'),
('PUN','prezzo','Prezzo Unico Nazionale. Media dei prezzi zonali del MGP, ponderata sui consumi. Riferimento per quasi tutte le formule PUN-indicizzate.'),
('PSV','prezzo','Punto di Scambio Virtuale (gas). L''hub virtuale dove avvengono le contrattazioni del gas in Italia.'),
('CMEM','prezzo','Componente mercato del gas (media mensile prezzo PSV). Input chiave per la tutela vulnerabilità gas.'),
('CCR','prezzo','Componente copertura costi di approvvigionamento (gas). Copre rischi pro die, rischio bilanciamento, rischio profilo invernale, stoccaggio.'),
('QVD','prezzo','Componente Commercializzazione Vendita Dettaglio (gas). Il margine riconosciuto al venditore tutela vulnerabilità.'),
('PCV','prezzo','Prezzo Commercializzazione Vendita (elettrico). Analogo QVD ma per l''elettrico MT.'),
('RCV','prezzo','Remunerazione Commercializzazione Vendita. Differenziate per dimensione dell''esercente MT (RCV grandi, RCVsm piccoli, RCVi integrati).'),
('PED','prezzo','Prezzo Energia e Dispacciamento (componente elettrica MT).'),
('PPE','prezzo','Prezzo Perequazione Energia. Squilibri di perequazione scaricati sui clienti MT.'),
('DISPBT','prezzo','Componente di dispacciamento in bassa tensione, a copertura dei meccanismi perequativi.'),
('Asos','prezzo','Componente tariffaria a copertura degli incentivi alle rinnovabili e cogenerazione. Uno degli oneri di sistema più pesanti.'),
('Switching','processi','Cambio fornitore. Regolato dalla delibera 487/2015/R/eel (elettrico) e 77/2018/R/com (gas). Tempistica standard: entro il mese successivo alla richiesta.'),
('Voltura','processi','Cambio intestatario della fornitura senza interruzione.'),
('Subentro','processi','Riattivazione di fornitura dopo chiusura con lo stesso o diverso intestatario.'),
('POD','processi','Point of Delivery (elettrico). Codice univoco del punto di prelievo elettrico.'),
('PDR','processi','Punto di Riconsegna (gas). Equivalente POD per il gas.'),
('Dispacciamento','processi','Gestione in tempo reale dell''equilibrio tra immissioni e prelievi. Costi scaricati via corrispettivi TIDE/TIS.'),
('Unpaid Ratio','processi','UR. Quota di fatturato non incassato in un dato periodo. Indicatore chiave della qualità del portafoglio clienti di un reseller.'),
('Perequazione','processi','Meccanismi che redistribuiscono costi/ricavi tra operatori per allineare il riconoscimento normativo ai costi effettivi.'),
('Ripensamento','processi','Diritto di recesso entro 14 giorni per contratti stipulati fuori dai locali o a distanza (Codice del Consumo).'),
('Variazione unilaterale','processi','Facoltà del venditore di modificare condizioni contrattuali per giustificato motivo. Preavviso 3 mesi obbligatorio (CCC art. 13).'),
('Evoluzione automatica','processi','Variazione già prevista in contratto (es. scadenza sconto promozionale). Preavviso 2 mesi obbligatorio.'),
('Rinnovo con modifica','processi','Scadenza condizioni economiche a termine con nuova proposta. Preavviso 3 mesi obbligatorio.'),
('Costituzione in mora','processi','Atto formale (raccomandata/PEC) con cui il venditore attiva la procedura per morosità.'),
('Cliente vulnerabile','segmenti','Definito dal DL 115/2022 (gas) e DLgs 210/2021 (elettrico). Categorie: over 75, disabili L.104, ISEE sotto soglia, utenti salvavita, strutture emergenziali. Identificazione automatica via SII.'),
('Cliente domestico','segmenti','Persona fisica, abitazione, BT ≤ 15 kW (distinto tra residente e non residente).'),
('Microimpresa','segmenti','< 10 dipendenti, fatturato o attivo ≤ 2 mln €.'),
('Piccola impresa','segmenti','< 50 dipendenti, fatturato o attivo ≤ 10 mln €.'),
('Cliente non domestico BT','segmenti','Commercio, servizi, artigiani connessi in bassa tensione.'),
('Cliente MT/AT','segmenti','Media o Alta Tensione. Industriali di dimensioni rilevanti. Salvaguardia e mercato libero; nessuna tutela.'),
('Bolletta 2.0','evoluzioni','Nuova Bolletta 2025. Dal 1° luglio 2025 nuovo formato bolletta definito da ARERA. Frontespizio unificato, sezione trasparenza separata.'),
('Codice Offerta','evoluzioni','RCU. Codice alfanumerico 32 caratteri identificativo di ogni offerta commerciale. Obbligatorio per iscrizione Portale Offerte.'),
('Portale Offerte','evoluzioni','ilportaleofferte.it. Piattaforma pubblica di confronto offerte. Delibera 51/2018/R/com. Ogni reseller deve popolarlo con tutte le offerte domestici e PMI.'),
('CER','evoluzioni','Comunità Energetiche Rinnovabili. Aggregazioni prosumer/consumer. Decreto CER 2024. Nuova frontiera per i reseller (valore aggiunto).'),
('CACER','evoluzioni','Configurazioni di Autoconsumo per l''energia rinnovabile (cappello normativo sopra CER, GAC, autoconsumo individuale a distanza).'),
('PUN Index GME','evoluzioni','Pubblicato mensilmente da GME, è il valore di riferimento per le STG e per molte offerte retail variabili.')
